#include <bits/stdc++.h>
using namespace std;
int n,f[102][102];
int main(){
    memset(f,127,sizeof(f));
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++){
            int a;
            scanf("%d",&a);
            if(a)
                f[i][j]=1;
        }
    for(int k=1;k<=n;k++)
        for(int i=1;i<=n;i++)
            for(int j=1;j<=n;j++)
                if(f[i][k]<1<<30 && f[k][j]<1<<30)
                    f[i][j]=min(f[i][j],f[i][k]+f[k][j]);
    for(int i=1;i<=n;i++){
        for(int j=1;j<=n;j++){
            if(f[i][j]<1<<30)
                printf("1 ");
            else
                printf("0 ");
        }
        printf("\n");
    }
    return 0;
}
